patch:
--- a/counter.sv
+++ b/counter.sv
@@ -1,15 +1,15 @@
 module counter_32bit (
   input clk,
   input rst_n,
   input enable,
   output reg [31:0] count
 );

-  always @(posedge clk) begin
+  always @(posedge clk or negedge rst_n) begin
     if (!rst_n)
       count <= 32'h0;
     else if (enable)
       count <= count + 1;
   end
 endmodule

before_code:
module counter_32bit (
  input clk,
  input rst_n,
  input enable,
  output reg [31:0] count
);

  always @(posedge clk) begin
    if (!rst_n)
      count <= 32'h0;
    else if (enable)
      count <= count + 1;
  end
endmodule

after_code:
module counter_32bit (
  input clk,
  input rst_n,
  input enable,
  output reg [31:0] count
);

  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      count <= 32'h0;
    else if (enable)
      count <= count + 1;
  end
endmodule
